"use strict";(globalThis.webpackChunkmimic_docs=globalThis.webpackChunkmimic_docs||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/docs/","label":"MimicAPI","docId":"intro","unlisted":false},{"type":"link","href":"/docs/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"category","label":"API Reference","collapsed":false,"items":[{"type":"link","href":"/docs/api/core","label":"CoreAPI","docId":"api/core","unlisted":false},{"type":"link","href":"/docs/api/player","label":"PlayerAPI","docId":"api/player","unlisted":false},{"type":"link","href":"/docs/api/actor","label":"ActorAPI","docId":"api/actor","unlisted":false},{"type":"link","href":"/docs/api/room","label":"RoomAPI","docId":"api/room","unlisted":false},{"type":"link","href":"/docs/api/manager","label":"ManagerAPI","docId":"api/manager","unlisted":false},{"type":"link","href":"/docs/api/loot","label":"LootAPI","docId":"api/loot","unlisted":false},{"type":"link","href":"/docs/api/server-network","label":"ServerNetworkAPI","docId":"api/server-network","unlisted":false},{"type":"link","href":"/docs/api/reflection","label":"ReflectionHelper","docId":"api/reflection","unlisted":false}],"collapsible":true}]},"docs":{"api/actor":{"id":"api/actor","title":"ActorAPI","description":"ActorAPI works with server-side actors inside a room \u2014 players (VPlayer), monsters (VMonster), and loot objects (VLootingObject). All actors are returned as object since these types can\'t be referenced directly from a mod.","sidebar":"tutorialSidebar"},"api/core":{"id":"api/core","title":"CoreAPI","description":"CoreAPI is the entry point for the game object hierarchy. Everything else in MimicAPI goes through these three objects.","sidebar":"tutorialSidebar"},"api/loot":{"id":"api/loot","title":"LootAPI","description":"LootAPI finds and works with LootingLevelObject instances in the Unity scene. These are the physical loot objects placed in the world \u2014 different from server-side loot tracked by ActorAPI.","sidebar":"tutorialSidebar"},"api/manager":{"id":"api/manager","title":"ManagerAPI","description":"ManagerAPI gives you access to all the game managers stored on Hub. Because they are C# auto-properties, their backing fields follow the kBackingField pattern \u2014 ManagerAPI handles that for you.","sidebar":"tutorialSidebar"},"api/player":{"id":"api/player","title":"PlayerAPI","description":"PlayerAPI works with client-side players via ProtoActor \u2014 Unity MonoBehaviour objects you can interact with directly. This is different from ActorAPI which works with server-side player representations inside rooms.","sidebar":"tutorialSidebar"},"api/reflection":{"id":"api/reflection","title":"ReflectionHelper","description":"ReflectionHelper is the low-level utility that all other APIs use internally. You only need it directly when you want to access game data that no API exposes yet.","sidebar":"tutorialSidebar"},"api/room":{"id":"api/room","title":"RoomAPI","description":"RoomAPI gives you access to the game\'s server-side rooms. Rooms are returned as object because IVroom is a game type that can\'t be referenced directly from a mod \u2014 just pass them back into RoomAPI methods and everything works.","sidebar":"tutorialSidebar"},"api/server-network":{"id":"api/server-network","title":"ServerNetworkAPI","description":"ServerNetworkAPI exposes the game\'s server networking layer \u2014 sessions, connections, and the two transport servers (RUDPServer for UDP, SDRServer for Steam relay). Most of this is only meaningful on the host.","sidebar":"tutorialSidebar"},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Requirements","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"MimicAPI","description":"MimicAPI is a modding library for Mimesis built on top of MelonLoader. It wraps the game\'s internal server-side types \u2014 which aren\'t directly accessible from mods \u2014 and exposes them through a clean, reflection-based API.","sidebar":"tutorialSidebar"}}}}')}}]);